/* Grupo II Q1 — Master/slave: fatorial distribuido por N slaves (pipes bidirecionais) */
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <stdio.h>
#include <stdlib.h>

#define N_SLAVES 3          /* numero fixo de processos slave              */
#define MAX_VALUES 100      /* capacidade maxima de leitura do stdin       */
/* Uma tarefa: o indice original (para reordenar) e o valor a processar.   */
typedef struct {
    int index;              /* posicao original na entrada                 */
    int value;              /* valor cujo fatorial vamos calcular          */
} task_t;

/* Um resultado: mesmo indice + o fatorial calculado.                      */
typedef struct {
    int index;
    long long result;
} result_t;

static long long factorial(int n) {
    long long f = 1;
    for (int k = 2; k <= n; k++) f *= k;
    return f;
}
int main(void) {
    int to_slave[N_SLAVES][2];    /* master -> slave i                     */
    int to_master[N_SLAVES][2];   /* slave i -> master                     */
    pid_t pids[N_SLAVES];
    int values[MAX_VALUES];
    long long results[MAX_VALUES];
    int m = 0, i, v;

    /* Ler os M inteiros do stdin (guardando a ordem de leitura).          */
    while (m < MAX_VALUES && scanf("%d", &v) == 1)
        values[m++] = v;
    /* Criar TODOS os pipes antes de qualquer fork().                      */
    for (i = 0; i < N_SLAVES; i++) {
        if (pipe(to_slave[i]) == -1 || pipe(to_master[i]) == -1) {
            perror("pipe");
            exit(EXIT_FAILURE);
        }
    }
    /* ---------------- criar os N slaves ---------------- */
    for (i = 0; i < N_SLAVES; i++) {
        if ((pids[i] = fork()) == -1) {
            perror("fork");
            exit(EXIT_FAILURE);
        }
        if (pids[i] == 0) {
            /* ===== SLAVE i ===== */
            task_t t;
            result_t r;
            int j;
            /* higiene de fds: este slave so le do SEU to_slave e escreve
             * no SEU to_master; fecha tudo o resto.                       */
            for (j = 0; j < N_SLAVES; j++) {
                if (j != i) { close(to_slave[j][0]); close(to_slave[j][1]);
                              close(to_master[j][0]); close(to_master[j][1]); }
            }
            close(to_slave[i][1]);    /* nao escrevo no meu pipe de entrada */
            close(to_master[i][0]);   /* nao leio do meu pipe de saida      */

            /* processar tarefas ate EOF (master fecha o pipe no fim)      */
            while (read(to_slave[i][0], &t, sizeof(task_t)) > 0) {
                r.index = t.index;
                r.result = factorial(t.value);
                write(to_master[i][1], &r, sizeof(result_t));
            }
            close(to_slave[i][0]);
            close(to_master[i][1]);
            exit(EXIT_SUCCESS);
        }
    }
    /* ===== MASTER ===== */
    task_t t;
    result_t r;
    /* higiene de fds: master escreve nos to_slave e le dos to_master.     */
    for (i = 0; i < N_SLAVES; i++) {
        close(to_slave[i][0]);    /* master nao le pedidos                 */
        close(to_master[i][1]);   /* master nao escreve resultados         */
    }

    /* distribuir os M valores pelos N slaves (round-robin).               */
    for (i = 0; i < m; i++) {
        t.index = i;
        t.value = values[i];
        write(to_slave[i % N_SLAVES][1], &t, sizeof(task_t));
    }
    /* fechar os pipes de entrada: assim cada slave ve EOF e termina.      */
    for (i = 0; i < N_SLAVES; i++)
        close(to_slave[i][1]);

    /* recolher resultados de cada slave ate EOF; guardar por indice.      */
    for (i = 0; i < N_SLAVES; i++) {
        while (read(to_master[i][0], &r, sizeof(result_t)) > 0)
            results[r.index] = r.result;
        close(to_master[i][0]);
    }
    for (i = 0; i < N_SLAVES; i++)
        waitpid(pids[i], NULL, 0);

    /* imprimir pela ordem de leitura do stdin.                            */
    for (i = 0; i < m; i++)
        printf("%d! = %lld\n", values[i], results[i]);
    return 0;
}

