/* Grupo II Q1 — Coordenador/trabalhadores: custo de encomendas (pipes bidirecionais) */
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <stdio.h>
#include <stdlib.h>

#define N_WORKERS 3         /* numero fixo de processos trabalhadores      */
#define MAX_ORDERS 100      /* capacidade maxima de leitura do stdin       */
#define UNIT_PRICE 10       /* valor fixo por unidade                      */
/* Um pedido: indice original (para reordenar) + numero de unidades.       */
typedef struct {
    int index;
    int units;
} order_t;

/* Um resultado: mesmo indice + custo total calculado.                     */
typedef struct {
    int index;
    int cost;
} result_t;
int main(void) {
    int to_worker[N_WORKERS][2];    /* coordenador -> trabalhador i        */
    int to_coord[N_WORKERS][2];     /* trabalhador i -> coordenador        */
    pid_t pids[N_WORKERS];
    int orders[MAX_ORDERS];
    int costs[MAX_ORDERS];
    int m = 0, i, v;

    /* Ler os M pedidos do stdin (guardando a ordem de leitura).           */
    while (m < MAX_ORDERS && scanf("%d", &v) == 1)
        orders[m++] = v;
    /* Criar TODOS os pipes antes de qualquer fork().                      */
    for (i = 0; i < N_WORKERS; i++) {
        if (pipe(to_worker[i]) == -1 || pipe(to_coord[i]) == -1) {
            perror("pipe");
            exit(EXIT_FAILURE);
        }
    }
    /* ---------------- criar os N trabalhadores ---------------- */
    for (i = 0; i < N_WORKERS; i++) {
        if ((pids[i] = fork()) == -1) {
            perror("fork");
            exit(EXIT_FAILURE);
        }
        if (pids[i] == 0) {
            /* ===== TRABALHADOR i ===== */
            order_t o;
            result_t r;
            int j;
            /* higiene de fds: le so do SEU to_worker, escreve no SEU
             * to_coord; fecha tudo o resto.                               */
            for (j = 0; j < N_WORKERS; j++) {
                if (j != i) { close(to_worker[j][0]); close(to_worker[j][1]);
                              close(to_coord[j][0]); close(to_coord[j][1]); }
            }
            close(to_worker[i][1]);
            close(to_coord[i][0]);

            while (read(to_worker[i][0], &o, sizeof(order_t)) > 0) {
                r.index = o.index;
                r.cost = o.units * UNIT_PRICE;
                write(to_coord[i][1], &r, sizeof(result_t));
            }
            close(to_worker[i][0]);
            close(to_coord[i][1]);
            exit(EXIT_SUCCESS);
        }
    }
    /* ===== COORDENADOR ===== */
    order_t o;
    result_t r;
    for (i = 0; i < N_WORKERS; i++) {
        close(to_worker[i][0]);
        close(to_coord[i][1]);
    }

    /* distribuir os M pedidos pelos N trabalhadores (round-robin).        */
    for (i = 0; i < m; i++) {
        o.index = i;
        o.units = orders[i];
        write(to_worker[i % N_WORKERS][1], &o, sizeof(order_t));
    }
    for (i = 0; i < N_WORKERS; i++)
        close(to_worker[i][1]);

    /* recolher resultados ate EOF; guardar por indice original.           */
    for (i = 0; i < N_WORKERS; i++) {
        while (read(to_coord[i][0], &r, sizeof(result_t)) > 0)
            costs[r.index] = r.cost;
        close(to_coord[i][0]);
    }
    for (i = 0; i < N_WORKERS; i++)
        waitpid(pids[i], NULL, 0);

    /* imprimir pela ordem de entrada.                                     */
    for (i = 0; i < m; i++)
        printf("Encomenda %d (%d unidades): custo = %d\n", i, orders[i], costs[i]);
    return 0;
}

