/* Grupo II Q1 — Pesquisa paralela no array sales com 10 processos (pipe unidirecional filho->pai) */
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <stdio.h>
#include <stdlib.h>

#define NUM_RECORDS 1000000     /* total de registos de venda              */
#define NUM_PROC 10             /* numero de processos filho               */
#define SEG (NUM_RECORDS / NUM_PROC)  /* 100 000 registos por processo     */
#define THRESHOLD 2000          /* criterio: quantity > 2000               */
/* Um registo de venda.                                                    */
typedef struct {
    int customer_code;
    int product_code;
    int quantity;
} sale_t;

/* sales e larger sao globais: o array sales e preenchido ANTES do fork(),
 * por isso cada filho herda-o por copia (copy-on-write). larger e usado
 * apenas pelo pai para acumular os codigos recebidos.                     */
sale_t sales[NUM_RECORDS];
int larger[NUM_RECORDS];
int main(void) {
    int fd[NUM_PROC][2];        /* um pipe por filho (filho -> pai)        */
    pid_t pids[NUM_PROC];
    int i, count = 0, code;

    /* Preencher o array sales com valores aleatorios (ja dado no enunciado).
     * Poucos registos ultrapassam o limiar, para o output ser legivel.    */
    srand(42);
    for (i = 0; i < NUM_RECORDS; i++) {
        sales[i].customer_code = rand() % 100000;
        sales[i].product_code = rand() % 100000;
        sales[i].quantity = rand() % 2001;              /* 0..2000         */
        if (rand() % 5000 == 0)                         /* pico raro       */
            sales[i].quantity = THRESHOLD + 1 + rand() % 1000;
    }
    /* Criar TODOS os pipes antes de qualquer fork().                      */
    for (i = 0; i < NUM_PROC; i++) {
        if (pipe(fd[i]) == -1) {
            perror("pipe");
            exit(EXIT_FAILURE);
        }
    }
    /* ---------------- criar os 10 processos filho ---------------- */
    for (i = 0; i < NUM_PROC; i++) {
        if ((pids[i] = fork()) == -1) {
            perror("fork");
            exit(EXIT_FAILURE);
        }
        if (pids[i] == 0) {
            /* ===== FILHO i: pesquisa o seu segmento ===== */
            int j, start = i * SEG, end = start + SEG;
            /* higiene de fds: o filho so ESCREVE no seu pipe.             */
            for (j = 0; j < NUM_PROC; j++)
                close(fd[j][0]);            /* nenhum filho le             */
            for (j = 0; j < NUM_PROC; j++)
                if (j != i) close(fd[j][1]); /* fecha os pipes dos outros  */

            for (j = start; j < end; j++) {
                if (sales[j].quantity > THRESHOLD)
                    write(fd[i][1], &sales[j].product_code, sizeof(int));
            }
            close(fd[i][1]);                /* fecho => pai ve EOF         */
            exit(EXIT_SUCCESS);
        }
    }
    /* ===== PAI: recolhe os codigos de cada filho ===== */
    for (i = 0; i < NUM_PROC; i++)
        close(fd[i][1]);                    /* pai nunca escreve          */

    /* ler de cada pipe ate EOF (o filho i so termina quando fecha).       */
    for (i = 0; i < NUM_PROC; i++) {
        while (read(fd[i][0], &code, sizeof(int)) > 0)
            larger[count++] = code;
        close(fd[i][0]);
    }
    for (i = 0; i < NUM_PROC; i++)
        waitpid(pids[i], NULL, 0);

    /* imprimir o conteudo de larger.                                      */
    printf("Encontrados %d registos com quantity > %d:\n", count, THRESHOLD);
    for (i = 0; i < count; i++)
        printf("larger[%d] = %d\n", i, larger[i]);
    return 0;
}

